# Category: oauth_security

from flask import Flask, request, jsonify
from urllib.parse import urlparse

app = Flask(__name__)

# Example registered base URI
registered_uri = "https://example.com/oauth/callback"

@app.route('/authorize', methods=['GET'])
def authorize():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri or not validate_redirect_uri(redirect_uri):
        return jsonify({'error': 'invalid_redirect_uri'}), 400
    
    # Proceed with the authorization process
    return jsonify({'message': 'Authorization successful', 'redirect_uri': redirect_uri})

def validate_redirect_uri(uri):
    parsed_uri = urlparse(uri)
    return parsed_uri.scheme in ['http', 'https'] and uri.startswith(registered_uri)

if __name__ == '__main__':
    app.run(debug=True)